+// Minimap room colors for the 9 rooms
+const MINIMAP_ROOM_COLORS: Record<string, string> = {
+  king: '#FFD700',        // gold (Throne)
+  squire: '#FF8C00',      // orange (Workshop)
+  judge: '#6A4B2A',       // brown (Scribe - mapped to judge tier for brown)
+  scribe: '#6A4B2A',      // brown (Scribe)
+  knight: '#B22222',      // red (War Room)
+  healer: '#228B22',      // green (Healing)
+  sentinel: '#808080',    // gray (Watchtower)
+  blacksmith: '#2F4F4F',  // dark gray (Dungeon)
+  nobility: '#800080',    // purple (Great Hall)
+};
+
+// Map ROOM_GRID labels to requested room names and colors
+// We have to map existing tiers to requested rooms:
+// Throne (king), Workshop (squire), Library (scribe), War Room (knight),
+// Healing (healer), Watchtower (sentinel), Scribe (scribe),
+// Dungeon (blacksmith), Great Hall (nobility)
+
+const MINIMAP_ROOM_LABELS: Record<string, string> = {
+  king: 'Throne',
+  squire: 'Workshop',
+  scribe: 'Library',
+  knight: 'War Room',
+  healer: 'Healing',
+  sentinel: 'Watchtower',
+  scribe: 'Scribe',
+  blacksmith: 'Dungeon',
+  nobility: 'Great Hall',
+};
+
+// Because scribe tier is used for both Library and Scribe rooms in original ROOM_GRID,
+// and judge tier is not in requested rooms, we will treat judge as Scribe room for minimap.
+
+// We will draw minimap in top-right corner, 160x120 px
+function drawMinimap(ctx: CanvasRenderingContext2D, agents: AgentInfo[]) {
+  const width = 160;
+  const height = 120;
+  const padding = 6;
+  const roomCols = 3;
+  const roomRows = 3;
+  const roomW = Math.floor((width - padding * (roomCols + 1)) / roomCols);
+  const roomH = Math.floor((height - padding * (roomRows + 1)) / roomRows);
+
+  // Dark semi-transparent background
+  ctx.save();
+  ctx.fillStyle = 'rgba(20, 20, 30, 0.8)';
+  ctx.fillRect(ctx.canvas.width - width - 10, 10, width, height);
+
+  // Draw rooms as colored rectangles
+  // We will use ROOM_GRID to position rooms by col,row but only for the 9 requested rooms
+  // Map tier to minimap room color and position
+  // Agents grouped by tier for dots
+  const agentsByTier = new Map<string, AgentInfo[]>();
+  for (const a of agents) {
+    const list = agentsByTier.get(a.tier) ?? [];
+    list.push(a);
+    agentsByTier.set(a.tier, list);
+  }
+
+  // We define the 9 rooms with their tier keys and positions in a 3x3 grid for minimap
+  // Use the same ROOM_GRID but adjust for missing or different labels
+  // We'll create a fixed array for minimap rooms with tier, col, row, and color
+  const minimapRooms = [
+    { tier: 'king',       label: 'Throne',    col: 1, row: 0, color: '#FFD700' },   // gold
+    { tier: 'squire',     label: 'Workshop',  col: 0, row: 1, color: '#FF8C00' },   // orange
+    { tier: 'scribe',     label: 'Library',   col: 2, row: 0, color: '#0000FF' },   // blue
+    { tier: 'knight',     label: 'War Room',  col: 1, row: 1, color: '#B22222' },   // red
+    { tier: 'healer',     label: 'Healing',   col: 1, row: 2, color: '#228B22' },   // green
+    { tier: 'sentinel',   label: 'Watchtower',col: 2, row: 1, color: '#808080' },   // gray
+    { tier: 'scribe',     label: 'Scribe',    col: 0, row: 2, color: '#6A4B2A' },   // brown
+    { tier: 'blacksmith', label: 'Dungeon',   col: 0, row: 0, color: '#2F4F4F' },   // dark gray
+    { tier: 'nobility',   label: 'Great Hall',col: 2, row: 2, color: '#800080' },   // purple
+  ];
+
+  // Draw each room rectangle and agent dots inside
+  minimapRooms.forEach(room => {
+    const rx = ctx.canvas.width - width - 10 + padding + room.col * (roomW + padding);
+    const ry = 10 + padding + room.row * (roomH + padding);
+
+    // Room background rectangle
+    ctx.fillStyle = room.color;
+    ctx.globalAlpha = 0.3;
+    ctx.fillRect(rx, ry, roomW, roomH);
+    ctx.globalAlpha = 1.0;
+
+    // Room border
+    ctx.strokeStyle = '#222';
+    ctx.lineWidth = 1;
+    ctx.strokeRect(rx, ry, roomW, roomH);
+
+    // Draw agent dots inside room
+    const roomAgents = agentsByTier.get(room.tier) ?? [];
+    const dotRadius = 4;
+    const maxDotsPerRow = Math.floor(roomW / (dotRadius * 2 + 2));
+    const dotSpacing = dotRadius * 2 + 2;
+    roomAgents.forEach((agent, i) => {
+      if (i >= maxDotsPerRow * 2) return; // limit dots to two rows max
+      const dotX = rx + 4 + (i % maxDotsPerRow) * dotSpacing;
+      const dotY = ry + 4 + Math.floor(i / maxDotsPerRow) * dotSpacing;
+      // Dot color by agent tier color or fallback
+      const dotColor = MINIMAP_ROOM_COLORS[agent.tier] ?? '#fff';
+      ctx.beginPath();
+      ctx.fillStyle = dotColor;
+      ctx.shadowColor = dotColor;
+      ctx.shadowBlur = 4;
+      ctx.arc(dotX, dotY, dotRadius, 0, Math.PI * 2);
+      ctx.fill();
+      ctx.shadowBlur = 0;
+    });
+  });
+
+  ctx.restore();
+}
